(function () {
  const SOURCE_MAP = {
    "#": "Row number generated by the page for easier scanning.",
    "actions": "Available commands for this row. These are shown only when your role has permission.",
    "active tasks": "Count of tasks that are not completed, calculated from project/task records.",
    "alert": "Generated by CRM risk rules using project due dates, phase due dates, payment status, stale activity, Oracle mismatches, and publication status.",
    "alerts": "Count of CRM alerts linked to this project or client risk item.",
    "amount": "Stored amount from finance payment, expenditure, forecast, or MOA records.",
    "assigned to": "User assigned to the task from project team membership.",
    "author": "Author details captured on book, chapter, paper, or conference records.",
    "book": "Book record from the research outputs module.",
    "category": "Finance expenditure category selected when the expense or forecast was captured.",
    "client": "Client/stakeholder name from the cost centre CRM record.",
    "client name": "Client/stakeholder name captured on the cost centre record.",
    "client/centre": "Research centre or client relationship inferred from the project and cost centre links.",
    "client phase due dates": "Phase dates captured on the cost centre/MOA record. CRM uses these dates for client-risk alerts.",
    "code": "University cost centre code stored on the cost centre record.",
    "company": "Company profile details stored on the cost centre CRM record.",
    "conference": "Conference output record from the research outputs module.",
    "cost centre": "Finance cost centre record. CRM treats this as the client/company relationship record.",
    "date": "Date stored on the related task, meeting, payment, expenditure, forecast, or output record.",
    "due date": "Due date stored on the project, task, book, phase, or output record. Overdue dates feed CRM risk alerts.",
    "email": "Email address stored on the user or company/contact profile.",
    "engagement": "Project record represented as a CRM engagement.",
    "expense id": "Unique external/import identifier used to prevent duplicate expenditure rows.",
    "industry": "Industry field captured on the company CRM profile.",
    "last contact": "Latest task activity date for the project; CRM treats old activity as retention risk.",
    "month": "Finance month derived from expenditure or forecast date ranges.",
    "moa amount": "Expected Memorandum of Understanding value captured on the cost centre record.",
    "name": "Name stored on the current row's model record.",
    "owner": "Responsible user inferred from the project lead, creator, assigned user, or output owner.",
    "paper": "Paper record from the research outputs module.",
    "pipeline": "MOA amount minus total received payments for the cost centre.",
    "primary contact": "Main contact person captured on the company CRM profile.",
    "priority": "Task priority selected when the task was created or edited.",
    "progress": "For tasks, progress is mapped from status: To Do 0%, In Progress 33%, Review 66%, Done 100%. For projects, progress is averaged from linked task progress.",
    "% progress": "Project progress is averaged from linked task progress. Task progress comes from task status.",
    "research centre": "Research centre foreign key on the user, cost centre, or project. It controls centre filtering.",
    "relationship owner": "Centre head or lead user associated with the client/cost centre relationship.",
    "revenue": "Total received payments summed from payment records for the cost centre.",
    "risk": "CRM risk level calculated from overdue dates, missing phase dates, stale activity, payments, and publication state.",
    "role": "User role stored on the user account. It controls permissions and navigation.",
    "severity": "Alert severity assigned by CRM risk rules.",
    "stage": "CRM lifecycle label derived from project status.",
    "status": "Current workflow status stored on the project, task, user, book, paper, conference, or finance record.",
    "team": "Number of assigned team members on the project.",
    "title": "Title stored on the project, task, book, paper, conference, or notification record.",
    "total moa amount": "Expected/budgeted MOA amount captured on the cost centre record.",
    "total moa outstanding": "MOA amount minus total received payments.",
    "total received": "Sum of all payment records linked to the cost centre.",
    "total spent": "Sum of all expenditure records linked to the cost centre.",
    "visibility": "CRM visibility label based on role and scope.",
  };

  function normalise(text) {
    return (text || "")
      .replace(/\s+/g, " ")
      .replace(/[^\w#%/ ]/g, "")
      .trim()
      .toLowerCase();
  }

  function explain(headerText) {
    const key = normalise(headerText);
    if (SOURCE_MAP[key]) return SOURCE_MAP[key];
    for (const [sourceKey, value] of Object.entries(SOURCE_MAP)) {
      if (key.includes(sourceKey) || sourceKey.includes(key)) return value;
    }
    return "This column is populated by the Django view for this page from the matching database record or calculated context value.";
  }

  function applyTableHeaderTooltips(root) {
    const scope = root || document;
    scope.querySelectorAll("table th").forEach((th) => {
      if (th.dataset.tooltipBound === "true") return;
      const text = th.textContent.trim();
      if (!text) return;
      const message = th.dataset.source || explain(text);
      th.dataset.bsToggle = "tooltip";
      th.dataset.bsPlacement = "top";
      th.dataset.bsContainer = "body";
      th.dataset.bsTitle = message;
      th.dataset.tooltipBound = "true";
      th.classList.add("table-heading-help");
      if (!th.querySelector(".table-heading-help-icon")) {
        const icon = document.createElement("i");
        icon.className = "bi bi-info-circle table-heading-help-icon";
        icon.setAttribute("aria-hidden", "true");
        th.appendChild(document.createTextNode(" "));
        th.appendChild(icon);
      }
      if (window.bootstrap && bootstrap.Tooltip) {
        new bootstrap.Tooltip(th);
      }
    });
  }

  function installObserver() {
    const observer = new MutationObserver((mutations) => {
      mutations.forEach((mutation) => {
        mutation.addedNodes.forEach((node) => {
          if (node.nodeType === 1) applyTableHeaderTooltips(node);
        });
      });
    });
    observer.observe(document.body, { childList: true, subtree: true });
  }

  document.addEventListener("DOMContentLoaded", function () {
    applyTableHeaderTooltips(document);
    installObserver();
  });
})();
